```cpp
#include <hexi/hexi.h>
#include <vector>
#include <string>
#include <cstdint>

struct NetworkPacket {
    uint32_t packet_id;
    std::string username;
    std::vector<uint32_t> scores;
    std::string metadata;

    void serialise(auto& stream) const {
        // Write packet_id
        stream << packet_id;

        // Write username with length prefix
        stream << hexi::prefixed(username);

        // Write scores count first, then the scores vector
        uint32_t count = static_cast<uint32_t>(scores.size());
        stream << count << scores;

        // Write null-terminated metadata
        stream << hexi::null_terminated(metadata);
    }
};

std::vector<uint8_t> serialize_packet(const NetworkPacket& packet) {
    // Create a buffer and wrap it with buffer_adaptor
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Serialize the packet using its serialise method
    packet.serialise(stream);

    return buffer;
}
```

**Key implementation details:**

1. **`packet_id`**: Written directly as `uint32_t` using `stream << packet_id`

2. **`username`**: Serialized with length prefix using `hexi::prefixed(username)` which writes the length followed by the string data

3. **`scores`**: First writes the count as `uint32_t`, then uses `operator<<` with the vector which internally calls `write_container` to write all elements

4. **`metadata`**: Serialized as null-terminated string using `hexi::null_terminated(metadata)`

5. **`serialize_packet`**: Creates a binary stream from a dynamic buffer, calls the packet's `serialise` method, and returns the buffer containing the serialized data

