#include <hexi/hexi.h>
#include <cstdint>
#include <span>
#include <stdexcept>

struct PacketHeader {
    uint32_t magic;
    uint16_t version;
    uint16_t flags;
};

PacketHeader read_header_with_span(const std::span<const uint8_t> buffer) {
    // Create buffer adaptor from span
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Get the read pointer (buffer_adaptor pointer method)
    const auto* read_ptr = adaptor.read_pointer();

    // Check available data (buffer_adaptor method)
    constexpr std::size_t header_size = sizeof(uint32_t) + sizeof(uint16_t) + sizeof(uint16_t);
    if (adaptor.available() < header_size) {
        throw std::runtime_error("Insufficient data for header");
    }

    // Get a zero-copy view of the header and read (binary_stream zero-copy operations)
    PacketHeader header;
    stream >> header.magic >> header.version >> header.flags;

    return header;
}
```

This implementation:

1. **Gets the read pointer**: Uses `buffer_adaptor::read_pointer()` to obtain a pointer to the current read position
2. **Checks available data**: Uses `buffer_adaptor::available()` to verify there's enough data (8 bytes) for the complete header
3. **Gets a zero-copy view**: Uses `binary_stream`'s extraction operator (`>>`) which provides efficient, zero-copy reading of the header fields with proper type handling and endianness support

The function demonstrates the use of both `buffer_adaptor`'s pointer/availability methods and `binary_stream`'s zero-copy deserialization operations.

