    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    stream << header;
    stream << hexi::null_terminated(message);
    return buffer;
}

TEST(BufferReadView, ReadHeaderAndMessage) {
    auto buffer = create_message_buffer(12345, "Hello World");

    MessagePacket packet = read_header_and_message(buffer);

    EXPECT_EQ(12345, packet.header);
