MessagePacket read_header_and_message(const std::span<const uint8_t> buffer) {
    MessagePacket packet;

    // Create buffer adaptor and stream
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    // Read header
    stream >> packet.header;

    // Get view of remaining data for the message
    auto remaining = stream.view();

    // Find null terminator and create string_view
    const char* start = reinterpret_cast<const char*>(remaining.data());
