TEST(TLSAllocator, ThreadExit) {
    tls_allocator_type<> allocator;

    enter_thread_with_allocator(allocator);
    auto* ptr = allocator.allocate();

    exit_thread_with_allocator(allocator);

    // Cleanup should happen in destructor
    allocator.deallocate(ptr);
}

