// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator for uint64_t with a pool of element_count blocks
    hexi::block_allocator<std::uint64_t, element_count> allocator;

    std::cout << "=== Demonstrating Block Allocator Free List Management ===\n\n";

    // Initially, the free list contains all pre-allocated blocks
    std::cout << "1. Initial state: Free list has " << element_count << " blocks\n";
    std::cout << "   Storage active count: " << allocator.storage_active_count << "\n";
    std::cout << "   Total allocs: " << allocator.total_allocs << "\n\n";

    // Allocate blocks - each allocate() calls pop() internally
    std::cout << "2. Allocating 5 blocks (each allocate calls pop() on free list):\n";
    std::vector<std::uint64_t*> blocks;
    for (size_t i = 0; i < 5; ++i) {
        auto* block = allocator.allocate();
        *block = i * 100;  // Write some data
        blocks.push_back(block);
        std::cout << "   Allocated block " << i << " at " << static_cast<void*>(block) 
                  << ", value: " << *block << "\n";
    }
    std::cout << "   Storage active count: " << allocator.storage_active_count << "\n";
    std::cout << "   Total allocs: " << allocator.total_allocs << "\n\n";

    // Deallocate some blocks - each deallocate() calls push() internally
    std::cout << "3. Deallocating 3 blocks (each deallocate calls push() on free list):\n";
    for (size_t i = 0; i < 3; ++i) {
        std::cout << "   Deallocating block at " << static_cast<void*>(blocks[i]) << "\n";
        allocator.deallocate(blocks[i]);
    }
    std::cout << "   Storage active count: " << allocator.storage_active_count << "\n";
    std::cout << "   Total allocs: " << allocator.total_allocs << "\n";
    std::cout << "   Total deallocs: " << allocator.total_deallocs << "\n\n";

    // Allocate again - will reuse blocks from free list (pop() returns recently pushed blocks)
    std::cout << "4. Allocating 2 more blocks (pop() reuses deallocated blocks from free list):\n";
    for (size_t i = 0; i < 2; ++i) {
        auto* block = allocator.allocate();
        *block = i * 200;
        std::cout << "   Allocated block at " << static_cast<void*>(block) 
                  << ", value: " << *block << "\n";
        blocks.push_back(block);
