template<size_t block_size = 1024>
std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Calculate how much data is actually available to read
    size_t available = storage.write_offset - storage.read_offset;

    // Determine how many bytes we can actually preview
    size_t bytes_to_copy = std::min(bytes_to_preview, available);

    // Create result vector and copy data from storage starting at read_offset without advancing it
    std::vector<uint8_t> result(bytes_to_copy);
    if (bytes_to_copy > 0) {
        for (size_t i = 0; i < bytes_to_copy; ++i) {
            result[i] = static_cast<uint8_t>(storage.storage[storage.read_offset + i]);
        }
    }
    return result;
}
