using namespace hexi::detail;

template<typename T>
std::size_t encode_varint(hexi::pmc::binary_stream_writer& writer, T value) {
    std::size_t bytes_written = 0;

    // Convert to unsigned to handle bitwise operations correctly
    using unsigned_t = std::make_unsigned_t<T>;
    unsigned_t uvalue = static_cast<unsigned_t>(value);

    do {
        // Extract lower 7 bits
        std::uint8_t byte = uvalue & 0x7F;
        uvalue >>= 7;

        // Set MSB if more bytes follow
        if (uvalue != 0) {
            byte |= 0x80;
        }

        // Write the byte
        writer << byte;
        bytes_written++;
    } while (uvalue != 0);

    return bytes_written;
}

template<typename T>
T decode_varint(hexi::pmc::binary_stream_reader& reader) {
    using unsigned_t = std::make_unsigned_t<T>;
    unsigned_t result = 0;
    int shift = 0;

    while (true) {
        std::uint8_t byte;
        reader >> byte;

        // Extract the lower 7 bits and add to result
        result |= static_cast<unsigned_t>(byte & 0x7F) << shift;

        // Check if this is the last byte (MSB is 0)
        if ((byte & 0x80) == 0) {
            break;
        }

        shift += 7;
    }

    return static_cast<T>(result);
}

template<typename T>
bool encode_decode_roundtrip(T original_value) {
    // Create a buffer to hold the encoded data
    std::vector<std::uint8_t> buffer;
    hexi::pmc::buffer_adaptor adaptor(buffer);

    // Encode the value
