#include <hexi/hexi.h>
#include <hexi/endian.h>
#include <vector>
#include <cstdint>
#include <string>
#include <bit>

struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Write sensor_id directly
        adaptor.write(sensor_id);

        // Write number of temperatures
        uint32_t temp_count = static_cast<uint32_t>(temperatures.size());
        adaptor.write(temp_count);

        // Convert and write each temperature
        for (const auto& temp : temperatures) {
            auto temp_le = hexi::endian::conditional_reverse(temp, std::endian::native, std::endian::little);
            adaptor.write(temp_le);
        }

        // Convert and write pressure
        auto pressure_le = hexi::endian::conditional_reverse(pressure, std::endian::native, std::endian::little);
        adaptor.write(pressure_le);
    }

    void serialise(auto& adaptor) {
        // Read sensor_id directly
        adaptor.read(sensor_id);

        // Read number of temperatures
        uint32_t temp_count;
        adaptor.read(temp_count);

        // Read and convert each temperature
        temperatures.resize(temp_count);
        for (auto& temp : temperatures) {
            adaptor.read(temp);
            hexi::endian::little_to_native_inplace(temp);
        }

        // Read and convert pressure
        adaptor.read(pressure);
        hexi::endian::little_to_native_inplace(pressure);
    }
};

std::vector<uint8_t> serialize_measurement_data(const MeasurementData& data) {
    std::vector<uint8_t> buffer;
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);
    stream.serialise(data);
    return buffer;
}

MeasurementData deserialize_measurement_data(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);
    MeasurementData data;
    stream.deserialise(data);
    return data;
}

struct SensorInfo {
    uint32_t sensor_id;
    std::string_view sensor_name;
};

SensorInfo extract_sensor_info(const std::span<const uint8_t> buffer) {
    hexi::buffer_adaptor adaptor(buffer);
    hexi::binary_stream stream(adaptor);

    SensorInfo info;

    // Extract null-terminated sensor name string using view
    info.sensor_name = stream.view();

    // Enforce read bounds before reading sensor_id
    stream.enforce_read_bounds(sizeof(uint32_t));

    // Read sensor_id directly
    stream.read(info.sensor_id);

    // Skip remaining data
    auto remaining = stream.size();
    if (remaining > 0) {
        stream.skip(remaining);
    }

    return info;
}
